from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
from datetime import datetime, timedelta
import redis
import time
import hashlib

app = Flask(__name__)

# Configuration
ELASTICSEARCH_HOST = 'localhost:9200'
REDIS_HOST = 'localhost'
REDIS_PORT = 6379

# Rate limiting configuration
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 100  # requests per window per IP

# Initialize connections
es = Elasticsearch([ELASTICSEARCH_HOST])
redis_client = redis.Redis(host=REDIS_HOST, port=REDIS_PORT, decode_responses=True)

def get_client_ip():
    """Get client IP address from request"""
    if request.headers.get('X-Forwarded-For'):
        return request.headers.get('X-Forwarded-For').split(',')[0].strip()
    return request.remote_addr

def rate_limit(max_requests=RATE_LIMIT_MAX_REQUESTS, window=RATE_LIMIT_WINDOW):
    """Rate limiting decorator"""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = get_client_ip()
            key = f"rate_limit:{client_ip}:{f.__name__}"
            
            try:
                current = redis_client.get(key)
                
                if current is None:
                    redis_client.setex(key, window, 1)
                    return f(*args, **kwargs)
                
                if int(current) >= max_requests:
                    return jsonify({
                        'error': 'Rate limit exceeded',
                        'message': 'Too many requests. Please try again later.'
                    }), 429
                
                redis_client.incr(key)
                return f(*args, **kwargs)
                
            except redis.RedisError:
                # If Redis is down, allow the request but log the error
                return f(*args, **kwargs)
        
        return wrapped
    return decorator

@app.route('/api/search', methods=['GET'])
@rate_limit(max_requests=100, window=60)
def search_products():
    """
    Search products endpoint with rate limiting
    GET /api/search?q=keyword&page=1&size=20
    """
    query = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    size = request.args.get('size', 20, type=int)
    
    # Validate input
    if not query:
        return jsonify({
            'error': 'Invalid request',
            'message': 'Search query is required'
        }), 400
    
    # Limit page size to prevent abuse
    if size > 100:
        size = 100
    
    if page < 1:
        page = 1
    
    # Calculate offset
    from_offset = (page - 1) * size
    
    try:
        # Elasticsearch query
        search_body = {
            'query': {
                'multi_match': {
                    'query': query,
                    'fields': ['name^3', 'description^2', 'category', 'tags'],
                    'fuzziness': 'AUTO'
                }
            },
            'from': from_offset,
            'size': size,
            'sort': [
                {'_score': {'order': 'desc'}},
                {'created_at': {'order': 'desc'}}
            ]
        }
        
        response = es.search(index='products', body=search_body)
        
        # Format results
        products = []
        for hit in response['hits']['hits']:
            product = hit['_source']
            product['id'] = hit['_id']
            product['score'] = hit['_score']
            products.append(product)
        
        total = response['hits']['total']['value']
        
        return jsonify({
            'success': True,
            'query': query,
            'total': total,
            'page': page,
            'size': size,
            'total_pages': (total + size - 1) // size,
            'products': products
        }), 200
        
    except Exception as e:
        # Generic error response - don't leak internal details
        return jsonify({
            'error': 'Search failed',
            'message': 'Unable to process search request. Please try again later.'
        }), 500

